import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import Greeting from './Greeting';

test('mostra mensagem ao clicar no botão', async () => {
  // Arrange — renderiza o componente
  render(<Greeting name="Maria" />);

  // Act — simula o clique do usuário
  const button = screen.getByRole('button', { name: /saudar/i });
  await userEvent.click(button);

  // Assert — verifica o resultado na tela
  expect(screen.getByText(/olá, maria/i)).toBeInTheDocument();
});
